# Hub-and-spoke: single risk gate, all BUs pass through
class CoERiskGate:
    def evaluate(self, use_case: UseCase) -> RiskVerdict:
        # One evaluation, one record, one audit trail
        tier = classify_risk(use_case)
        approvers = self._required_approvers(tier)
        return RiskVerdict(tier=tier, required_approvers=approvers, gate="CoE")

# Federated: each BU implements its own gate — divergence is inevitable
class BURiskGate:
    def __init__(self, bu_id: str, local_risk_policy: dict):
        self.bu_id = bu_id
        self.policy = local_risk_policy  # BU-specific → inconsistent enterprise risk posture

    def evaluate(self, use_case: UseCase) -> RiskVerdict:
        # BU may apply lighter or heavier criteria than enterprise standard
        tier = self.policy["classifier"](use_case)
        return RiskVerdict(tier=tier, required_approvers=self.policy["approvers"][tier], gate=self.bu_id)
